1	// Wire contract between the QEMU TCG plugin and vsim. Both sides write/read
2	// `struct hybrid_state_v1` byte-for-byte through a shared file.
3	//
4	// Stability: never repurpose offsets within a published version. Add new
5	// fields by consuming bytes from `reserved`, or by introducing v2 alongside.
6	//
7	// C and C++ both compile this header.
8	
9	#ifndef HYBRID_STATE_ABI_H
10	#define HYBRID_STATE_ABI_H
11	
12	#include <stdint.h>
13	#include <stddef.h>
14	
15	#ifdef __cplusplus
16	extern "C" {
17	#endif
18	
19	#define HYBRID_STATE_MAGIC   0x42594841u  // 'AHYB' little-endian
20	#define HYBRID_STATE_VERSION 1u
21	
22	#define HYBRID_FLAG_RV64 (1u << 0)
23	#define HYBRID_FLAG_FP   (1u << 1)
24	#define HYBRID_FLAG_V    (1u << 2)
25	
26	// VLEN upper bound, in bytes. Source of truth: data/configs/ax45mpv_premium.cfg
27	// which sets `NDS_VLEN 512` (-> 64 bytes per vector register). When that
28	// configured value changes, this constant must be updated in lock-step so
29	// the wire-format struct grows or shrinks to match the configured RVV width.
30	#define HYBRID_VLEN_BYTES_MAX 64
31	
32	// 64 PMP entries; pmpcfg slots reserved at 16 so the layout works for both
33	// RV64 (8 entries/CSR) and a future RV32 (4 entries/CSR) packing.
34	#define HYBRID_PMP_CFG_NUM  16
35	#define HYBRID_PMP_ADDR_NUM 64
36	
37	// All fields are naturally 8-byte aligned, so __attribute__((packed)) is
38	// unnecessary and would force unaligned access codegen. Layout is locked by
39	// the static_asserts in state_abi_check.h.
40	struct hybrid_state_v1 {
41	  uint32_t magic;
42	  uint32_t version;
43	  uint32_t flags;
44	  uint32_t hart_id;
45	  uint64_t pc;
46	  uint64_t priv;  // 0=U, 1=S, 3=M
47	
48	  uint64_t gpr[32];
49	  uint64_t fpr[32];
50	
51	  uint64_t mstatus;
52	  uint64_t mepc;
53	  uint64_t mtvec;
54	  uint64_t mcause;
55	  uint64_t mtval;
56	  uint64_t mscratch;
57	  uint64_t medeleg;
58	  uint64_t mideleg;
59	  uint64_t mip;
60	  uint64_t mie;
61	  uint64_t mcycle;
62	  uint64_t minstret;
63	  uint64_t satp;
64	
65	  uint64_t pmpcfg[HYBRID_PMP_CFG_NUM];
66	  uint64_t pmpaddr[HYBRID_PMP_ADDR_NUM];
67	
68	  uint64_t vstart;
69	  uint64_t vtype;
70	  uint64_t vl;
71	  uint64_t vlenb;
72	  uint8_t  vreg[32 * HYBRID_VLEN_BYTES_MAX];
73	  uint64_t vxsat;
74	  uint64_t vxrm;
75	  uint64_t vcsr;
76	
77	  uint8_t  reserved[232];  // zero-initialise on write; 256 - 3*8 (vxsat/vxrm/vcsr)
78	};
79	
80	#ifdef __cplusplus
81	}  // extern "C"
82	#endif
83	
84	#include "hybrid/state_abi_check.h"
85	
86	#endif  // HYBRID_STATE_ABI_H
87

1	// QEMU TCG plugin: drains architectural state and exits when the guest
2	// executes `csrwi 0x7C0, 0`. Shares hybrid/insn_match.h and
3	// hybrid/state_abi.h with the vsim side.
4	
5	#include "hybrid/handoff_site.h"
6	#include "hybrid/insn_match.h"
7	#include "hybrid/reg_names.h"
8	#include "hybrid/state_abi.h"
9	
10	#include "bbv_emit.h"
11	
12	#include <qemu-plugin.h>
13	
14	#include <glib.h>
15	
16	#include <fcntl.h>
17	#include <inttypes.h>
18	#include <stddef.h>
19	#include <stdint.h>
20	#include <stdio.h>
21	#include <stdlib.h>
22	#include <string.h>
23	#include <unistd.h>
24	#include <limits.h>
25	
26	QEMU_PLUGIN_EXPORT int qemu_plugin_version = QEMU_PLUGIN_VERSION;
27	
28	typedef struct {
29	    struct qemu_plugin_register *gpr[32];
30	    struct qemu_plugin_register *fpr[32];
31	    struct qemu_plugin_register *pc;
32	
33	    // M-mode CSRs as exposed by QEMU's gdbstub csr feature.
34	    struct qemu_plugin_register *mstatus;
35	    struct qemu_plugin_register *mepc;
36	    struct qemu_plugin_register *mtvec;
37	    struct qemu_plugin_register *mcause;
38	    struct qemu_plugin_register *mtval;
39	    struct qemu_plugin_register *mscratch;
40	    struct qemu_plugin_register *medeleg;
41	    struct qemu_plugin_register *mideleg;
42	    struct qemu_plugin_register *mip;
43	    struct qemu_plugin_register *mie;
44	    struct qemu_plugin_register *mcycle;
45	    struct qemu_plugin_register *minstret;
46	    struct qemu_plugin_register *satp;
47	
48	    struct qemu_plugin_register *pmpcfg[HYBRID_PMP_CFG_NUM];
49	    struct qemu_plugin_register *pmpaddr[HYBRID_PMP_ADDR_NUM];
50	
51	    struct qemu_plugin_register *vstart;
52	    struct qemu_plugin_register *vxsat;
53	    struct qemu_plugin_register *vxrm;
54	    struct qemu_plugin_register *vcsr;
55	    struct qemu_plugin_register *vtype;
56	    struct qemu_plugin_register *vl;
57	    struct qemu_plugin_register *vlenb;
58	    struct qemu_plugin_register *vreg[32];
59	
60	    // icount-trigger mode: per-vcpu retired-insn counter, incremented in
61	    // on_icount_tick. When icount_target is reached, the same drain path
62	    // as CSR/PC mode fires (on_handoff -> write_state_atomic -> exit 200).
63	    uint64_t icount_retired;
64	} VcpuRegs;
65	
66	static struct qemu_plugin_scoreboard *vcpu_state;
67	static char *outfile_path;
68	
69	// PC-trigger mode: when enter_pc_arg is non-zero (set via plugin arg
70	// `enter_pc=0x...`), the CSR-insn matcher is bypassed entirely and the
71	// drain callback is registered only for instructions whose vaddr equals
72	// enter_pc_arg. The kind reported on the drain is HYBRID_HANDOFF_ENTER
73	// (entry into vsim), matching CSR-mode `csrwi 0x7C0, 0` semantics.
74	static uint64_t enter_pc_arg;
75	static int pc_mode;
76	
77	// icount-trigger mode: when icount_target is non-zero (set via plugin arg
78	// `icount=N`), every translated insn gets an exec callback that bumps a
79	// per-vcpu counter; on threshold-cross the drain fires at that insn
80	// boundary. Coexists with CSR/PC modes - either trigger can win.
81	static uint64_t icount_target;
82	static int icount_mode;
83	
84	// BBV-emit mode (SimPoint profile): when bbv_mode is set (plugin args
85	// `bbv_out=PATH,slice=N`), every translated insn gets an exec callback
86	// that ticks a global BBV counter; one .bb row per N retired insns is
87	// flushed to PATH. Coexists with the drain triggers - independently
88	// registered before icount so that on co-firing (icount target == slice
89	// multiple) the slice row is emitted before exit(200).
90	static BbvEmit *bbv_emit;
91	static char    *bbv_out_path;
92	static uint64_t bbv_slice_target;
93	static int      bbv_mode;
94	
95	// Slice-consume mode (SimPoint replay; F11): when slice_consume_mode is
96	// set (plugin args `slice=N,slice_at=K`), the plugin counts slice
97	// boundaries (one boundary per N retired insns) and drains at the end
98	// of slice index K (0-based). With K=2 and slice=1000, drain fires at
99	// insn 3000 - the boundary that closes the third slice. The orchestrator
100	// chains one invocation per SimPoint cluster-representative slice idx.
101	// Shares the `slice=` parameter with BBV-emit; works independently of
102	// whether `bbv_out=` is also set.
103	static uint64_t slice_at_target;
104	static int      slice_consume_mode;
105	static uint64_t slice_consume_acc;
106	static uint64_t slice_consume_idx;
107	
108	static struct qemu_plugin_register *find_reg(GArray *regs, const char *name)
109	{
110	    for (guint i = 0; i < regs->len; i++) {
111	        qemu_plugin_reg_descriptor *rd =
112	            &g_array_index(regs, qemu_plugin_reg_descriptor, i);
113	        if (g_ascii_strcasecmp(rd->name, name) == 0) {
114	            return rd->handle;
115	        }
116	    }
117	    return NULL;
118	}
119	
120	// Lazily resolves register handles. The plugin's vcpu_init runs before
121	// QEMU has registered the dynamic gdb coprocessors (FPU, virtual, csr,
122	// vector), so qemu_plugin_get_registers() returns only the 33 core CPU
123	// regs at that moment. By the time the entry trigger fires, all dynamic
124	// features are registered and a fresh call returns the full list.
125	static void resolve_handles(VcpuRegs *v)
126	{
127	    g_autoptr(GArray) regs = qemu_plugin_get_registers();
128	    for (int i = 0; i < 32; i++) {
129	        v->gpr[i] = find_reg(regs, hybrid_gpr_names[i]);
130	        v->fpr[i] = find_reg(regs, hybrid_fpr_names[i]);
131	    }
132	    v->pc = find_reg(regs, "pc");
133	
134	    v->mstatus  = find_reg(regs, "mstatus");
135	    v->mepc     = find_reg(regs, "mepc");
136	    v->mtvec    = find_reg(regs, "mtvec");
137	    v->mcause   = find_reg(regs, "mcause");
138	    v->mtval    = find_reg(regs, "mtval");
139	    v->mscratch = find_reg(regs, "mscratch");
140	    v->medeleg  = find_reg(regs, "medeleg");
141	    v->mideleg  = find_reg(regs, "mideleg");
142	    v->mip      = find_reg(regs, "mip");
143	    v->mie      = find_reg(regs, "mie");
144	    v->mcycle   = find_reg(regs, "mcycle");
145	    v->minstret = find_reg(regs, "minstret");
146	    v->satp     = find_reg(regs, "satp");
147	
148	    char buf[16];
149	    for (int i = 0; i < HYBRID_PMP_CFG_NUM; i++) {
150	        g_snprintf(buf, sizeof(buf), "pmpcfg%d", i);
151	        v->pmpcfg[i] = find_reg(regs, buf);
152	    }
153	    for (int i = 0; i < HYBRID_PMP_ADDR_NUM; i++) {
154	        g_snprintf(buf, sizeof(buf), "pmpaddr%d", i);
155	        v->pmpaddr[i] = find_reg(regs, buf);
156	    }
157	
158	    v->vstart = find_reg(regs, "vstart");
159	    v->vxsat  = find_reg(regs, "vxsat");
160	    v->vxrm   = find_reg(regs, "vxrm");
161	    v->vcsr   = find_reg(regs, "vcsr");
162	    v->vtype  = find_reg(regs, "vtype");
163	    v->vl     = find_reg(regs, "vl");
164	    v->vlenb  = find_reg(regs, "vlenb");
165	    for (int i = 0; i < 32; i++) {
166	        g_snprintf(buf, sizeof(buf), "v%d", i);
167	        v->vreg[i] = find_reg(regs, buf);
168	    }
169	}
170	
171	static uint64_t read_reg64(struct qemu_plugin_register *h)
172	{
173	    if (!h) return 0;
174	    g_autoptr(GByteArray) buf = g_byte_array_new();
175	    int sz = qemu_plugin_read_register(h, buf);
176	    if (sz <= 0) return 0;
177	    uint64_t v = 0;
178	    memcpy(&v, buf->data, sz < 8 ? (size_t) sz : 8);
179	    return v;
180	}
181	
182	// Reads up to `dst_max` bytes from a register handle. Returns the byte
183	// count written (0 on failure or NULL handle). Used for vector regs whose
184	// width = vlenb bytes.
185	static size_t read_reg_bytes(struct qemu_plugin_register *h,
186	                             uint8_t *dst, size_t dst_max)
187	{
188	    if (!h || dst_max == 0) return 0;
189	    g_autoptr(GByteArray) buf = g_byte_array_new();
190	    int sz = qemu_plugin_read_register(h, buf);
191	    if (sz <= 0) return 0;
192	    size_t n = (size_t) sz < dst_max ? (size_t) sz : dst_max;
193	    memcpy(dst, buf->data, n);
194	    return n;
195	}
196	
197	// Atomic on POSIX: write to .tmp, fsync, rename.
198	static int write_state_atomic(const struct hybrid_state_v1 *s, const char *path)
199	{
200	    char tmp[PATH_MAX];
201	    g_snprintf(tmp, sizeof(tmp), "%s.tmp.%d", path, (int) getpid());
202	    int fd = open(tmp, O_WRONLY | O_CREAT | O_TRUNC, 0600);
203	    if (fd < 0) {
204	        perror("hybrid_handoff: open tmp");
205	        return -1;
206	    }
207	    ssize_t want = (ssize_t) sizeof(*s);
208	    ssize_t got = write(fd, s, sizeof(*s));
209	    if (got != want) {
210	        perror("hybrid_handoff: write");
211	        close(fd);
212	        unlink(tmp);
213	        return -1;
214	    }
215	    fsync(fd);
216	    close(fd);
217	    if (rename(tmp, path) != 0) {
218	        perror("hybrid_handoff: rename");
219	        unlink(tmp);
220	        return -1;
221	    }
222	    return 0;
223	}
224	
225	static void on_handoff(unsigned int vcpu_idx, void *udata)
226	{
227	    const HandoffSite *site = (const HandoffSite *) udata;
228	    if (site->kind != HYBRID_HANDOFF_ENTER) return;
229	
230	    VcpuRegs *v = qemu_plugin_scoreboard_find(vcpu_state, vcpu_idx);
231	    resolve_handles(v);
232	    struct hybrid_state_v1 s = {0};
233	    s.magic   = HYBRID_STATE_MAGIC;
234	    s.version = HYBRID_STATE_VERSION;
235	    s.flags   = HYBRID_FLAG_RV64;
236	    s.hart_id = vcpu_idx;
237	    s.priv    = 3;
238	    // PC via translation-time vaddr+size; reading the gdbstub PC inside the
239	    // exec callback can lag the actual current insn when V instructions
240	    // retire just before the trigger (TCG defers PC writes for performance).
241	    s.pc      = compute_handoff_pc(site);
242	    for (int i = 0; i < 32; i++) s.gpr[i] = read_reg64(v->gpr[i]);
243	
244	    // Floating-point: only set FP flag if at least one handle was bound,
245	    // i.e. QEMU advertised the FPU feature (D extension).
246	    int has_fp = 0;
247	    for (int i = 0; i < 32; i++) {
248	        s.fpr[i] = read_reg64(v->fpr[i]);
249	        if (v->fpr[i]) has_fp = 1;
250	    }
251	    if (has_fp) s.flags |= HYBRID_FLAG_FP;
252	
253	    s.mstatus  = read_reg64(v->mstatus);
254	    s.mepc     = read_reg64(v->mepc);
255	    s.mtvec    = read_reg64(v->mtvec);
256	    s.mcause   = read_reg64(v->mcause);
257	    s.mtval    = read_reg64(v->mtval);
258	    s.mscratch = read_reg64(v->mscratch);
259	    s.medeleg  = read_reg64(v->medeleg);
260	    s.mideleg  = read_reg64(v->mideleg);
261	    s.mip      = read_reg64(v->mip);
262	    s.mie      = read_reg64(v->mie);
263	    s.mcycle   = read_reg64(v->mcycle);
264	    s.minstret = read_reg64(v->minstret);
265	    s.satp     = read_reg64(v->satp);
266	
267	    for (int i = 0; i < HYBRID_PMP_CFG_NUM; i++)
268	        s.pmpcfg[i] = read_reg64(v->pmpcfg[i]);
269	    for (int i = 0; i < HYBRID_PMP_ADDR_NUM; i++)
270	        s.pmpaddr[i] = read_reg64(v->pmpaddr[i]);
271	
272	    // Vector: only set V flag if QEMU advertised the V extension. vlenb
273	    // bounds the per-register byte count copied into vreg[].
274	    s.vstart = read_reg64(v->vstart);
275	    s.vxsat  = read_reg64(v->vxsat);
276	    s.vxrm   = read_reg64(v->vxrm);
277	    s.vcsr   = read_reg64(v->vcsr);
278	    s.vtype  = read_reg64(v->vtype);
279	    s.vl     = read_reg64(v->vl);
280	    s.vlenb  = read_reg64(v->vlenb);
281	    if (v->vlenb && s.vlenb > 0) {
282	        s.flags |= HYBRID_FLAG_V;
283	        size_t bytes = s.vlenb < HYBRID_VLEN_BYTES_MAX
284	                     ? (size_t) s.vlenb
285	                     : (size_t) HYBRID_VLEN_BYTES_MAX;
286	        for (int i = 0; i < 32; i++)
287	            (void) read_reg_bytes(v->vreg[i],
288	                                  &s.vreg[(size_t) i * HYBRID_VLEN_BYTES_MAX],
289	                                  bytes);
290	    }
291	
292	    if (write_state_atomic(&s, outfile_path) != 0) {
293	        fprintf(stderr, "hybrid_handoff: failed to write state file\n");
294	        exit(2);
295	    }
296	    fprintf(stderr,
297	            "hybrid_handoff: drained state to %s (pc=%#" PRIx64 "), exiting\n",
298	            outfile_path, s.pc);
299	    // 200 == kExitHandoffToQemu in hybrid_vsim/src/hybrid/exit_codes.hpp.
300	    // Distinguishes drain from workload completion (0) so the orchestrator
301	    // can decide the next spawn.
302	    exit(200);
303	}
304	
305	// Per-insn tick for icount mode. udata is the per-insn HandoffSite
306	// pre-allocated at translation time, so on_handoff's compute_handoff_pc
307	// returns the lag-free post-trigger PC (same property as the CSR path).
308	static void on_icount_tick(unsigned int vcpu_idx, void *udata)
309	{
310	    VcpuRegs *v = qemu_plugin_scoreboard_find(vcpu_state, vcpu_idx);
311	    if (++v->icount_retired < icount_target) return;
312	    on_handoff(vcpu_idx, udata);
313	}
314	
315	// Per-insn tick for BBV-emit mode. udata is the bb_id (1-based) cast to
316	// pointer; that mapping is stable across calls because bbv_emit_assign_id
317	// is hashed by TB-start PC. The tick attributes one insn to the bb_id and
318	// flushes a slice row when the per-slice counter saturates.
319	static void on_bbv_tick(unsigned int vcpu_idx, void *udata)
320	{
321	    (void) vcpu_idx;
322	    uint64_t bb_id = (uint64_t) GPOINTER_TO_UINT(udata);
323	    bbv_emit_tick(bbv_emit, bb_id);
324	}
325	
326	// Per-insn tick for slice-consume mode (F11). Counts insns into the
327	// slice accumulator; on each slice boundary increments slice_consume_idx
328	// and resets the accumulator. Once slice_consume_idx exceeds the target
329	// slice index, drains via on_handoff at that same insn boundary. udata
330	// is the per-insn HandoffSite (allocated at translation time) so the
331	// post-trigger PC reaches on_handoff lag-free.
332	static void on_slice_consume_tick(unsigned int vcpu_idx, void *udata)
333	{
334	    if (++slice_consume_acc < bbv_slice_target) return;
335	    slice_consume_acc = 0;
336	    if (slice_consume_idx++ < slice_at_target) return;
337	    // After the post-increment above, slice_consume_idx == slice_at_target+1
338	    // (the count of fully retired slices). Log so the e2e test can verify
339	    // drain timing without relying on minstret (which is a cycle-counter
340	    // proxy on andes-ax45mpv and does not track plugin-counted insns).
341	    fprintf(stderr,
342	            "hybrid_handoff: slice-consume drain (idx=%" PRIu64
343	            " target=%" PRIu64 ")\n",
344	            slice_consume_idx, slice_at_target);
345	    on_handoff(vcpu_idx, udata);
346	}
347	
348	static void vcpu_tb_trans(qemu_plugin_id_t id, struct qemu_plugin_tb *tb)
349	{
350	    (void) id;
351	    size_t n = qemu_plugin_tb_n_insns(tb);
352	
353	    // BBV-mode: assign a stable bb_id to this TB (1-based, hashed by
354	    // TB-start vaddr). Same id is shared by every insn in the TB.
355	    uint64_t bb_id = 0;
356	    if (bbv_mode && n > 0) {
357	        uint64_t tb_pc = qemu_plugin_insn_vaddr(qemu_plugin_tb_get_insn(tb, 0));
358	        bb_id = bbv_emit_assign_id(bbv_emit, tb_pc);
359	    }
360	
361	    for (size_t i = 0; i < n; i++) {
362	        struct qemu_plugin_insn *insn = qemu_plugin_tb_get_insn(tb, i);
363	
364	        // BBV callback is registered BEFORE icount so that if both modes
365	        // fire on the same insn (icount target == slice multiple), the
366	        // slice row is emitted before exit(200) is called.
367	        if (bbv_mode) {
368	            qemu_plugin_register_vcpu_insn_exec_cb(
369	                insn, on_bbv_tick, QEMU_PLUGIN_CB_NO_REGS,
370	                GUINT_TO_POINTER((guint) bb_id));
371	        }
372	
373	        // Slice-consume callback (F11). Registered after BBV so a BBV
374	        // row at the same boundary is flushed first; ordering vs icount
375	        // is irrelevant (both drain).
376	        if (slice_consume_mode) {
377	            HandoffSite *site = g_new0(HandoffSite, 1);
378	            site->kind  = HYBRID_HANDOFF_ENTER;
379	            site->vaddr = qemu_plugin_insn_vaddr(insn);
380	            site->size  = (uint32_t) qemu_plugin_insn_size(insn);
381	            qemu_plugin_register_vcpu_insn_exec_cb(
382	                insn, on_slice_consume_tick, QEMU_PLUGIN_CB_R_REGS, site);
383	        }
384	
385	        if (icount_mode) {
386	            HandoffSite *site = g_new0(HandoffSite, 1);
387	            site->kind  = HYBRID_HANDOFF_ENTER;
388	            site->vaddr = qemu_plugin_insn_vaddr(insn);
389	            site->size  = (uint32_t) qemu_plugin_insn_size(insn);
390	            qemu_plugin_register_vcpu_insn_exec_cb(
391	                insn, on_icount_tick, QEMU_PLUGIN_CB_R_REGS, site);
392	        }
393	
394	        if (pc_mode) {
395	            // PC-trigger mode: vaddr-only match. qemu_plugin_insn_size lets
396	            // a future fixture park enter_pc on a compressed insn -- next-PC
397	            // is computed from the API-reported size, not assumed to be 4.
398	            if (qemu_plugin_insn_vaddr(insn) != enter_pc_arg) continue;
399	            HandoffSite *site = g_new0(HandoffSite, 1);
400	            site->kind  = HYBRID_HANDOFF_ENTER;
401	            site->vaddr = qemu_plugin_insn_vaddr(insn);
402	            site->size  = (uint32_t) qemu_plugin_insn_size(insn);
403	            qemu_plugin_register_vcpu_insn_exec_cb(
404	                insn, on_handoff, QEMU_PLUGIN_CB_R_REGS, site);
405	            continue;
406	        }
407	
408	        // CSR-trigger mode (default).
409	        size_t sz = qemu_plugin_insn_size(insn);
410	        if (sz != 4) continue;
411	        uint32_t raw = 0;
412	        if (qemu_plugin_insn_data(insn, &raw, sizeof(raw)) != sizeof(raw))
413	            continue;
414	        hybrid_handoff_kind kind = HYBRID_HANDOFF_NONE;
415	        if (!hybrid_match_handoff_insn(raw, &kind)) continue;
416	        HandoffSite *site = g_new0(HandoffSite, 1);
417	        site->kind  = kind;
418	        site->vaddr = qemu_plugin_insn_vaddr(insn);
419	        site->size  = (uint32_t) sz;
420	        qemu_plugin_register_vcpu_insn_exec_cb(
421	            insn, on_handoff, QEMU_PLUGIN_CB_R_REGS, site);
422	    }
423	}
