425	QEMU_PLUGIN_EXPORT int qemu_plugin_install(qemu_plugin_id_t id,
426	                                           const qemu_info_t *info,
427	                                           int argc, char **argv)
428	{
429	    (void) info;
430	    for (int i = 0; i < argc; i++) {
431	        g_auto(GStrv) tok = g_strsplit(argv[i], "=", 2);
432	        if (g_strcmp0(tok[0], "outfile") == 0 && tok[1]) {
433	            outfile_path = g_strdup(tok[1]);
434	        } else if (g_strcmp0(tok[0], "enter_pc") == 0 && tok[1]) {
435	            char *endp = NULL;
436	            unsigned long long v = g_ascii_strtoull(tok[1], &endp, 0);
437	            if (!endp || *endp != '\0') {
438	                fprintf(stderr, "hybrid_handoff: invalid enter_pc=%s\n",
439	                        tok[1]);
440	                return -1;
441	            }
442	            enter_pc_arg = (uint64_t) v;
443	            pc_mode = 1;
444	        } else if (g_strcmp0(tok[0], "icount") == 0 && tok[1]) {
445	            char *endp = NULL;
446	            unsigned long long v = g_ascii_strtoull(tok[1], &endp, 0);
447	            if (!endp || *endp != '\0' || v == 0) {
448	                fprintf(stderr, "hybrid_handoff: invalid icount=%s\n",
449	                        tok[1]);
450	                return -1;
451	            }
452	            icount_target = (uint64_t) v;
453	            icount_mode = 1;
454	        } else if (g_strcmp0(tok[0], "bbv_out") == 0 && tok[1]) {
455	            bbv_out_path = g_strdup(tok[1]);
456	            bbv_mode = 1;
457	        } else if (g_strcmp0(tok[0], "slice") == 0 && tok[1]) {
458	            char *endp = NULL;
459	            unsigned long long v = g_ascii_strtoull(tok[1], &endp, 0);
460	            if (!endp || *endp != '\0' || v == 0) {
461	                fprintf(stderr, "hybrid_handoff: invalid slice=%s\n",
462	                        tok[1]);
463	                return -1;
464	            }
465	            bbv_slice_target = (uint64_t) v;
466	        } else if (g_strcmp0(tok[0], "slice_at") == 0 && tok[1]) {
467	            char *endp = NULL;
468	            unsigned long long v = g_ascii_strtoull(tok[1], &endp, 0);
469	            if (!endp || *endp != '\0') {
470	                fprintf(stderr, "hybrid_handoff: invalid slice_at=%s\n",
471	                        tok[1]);
472	                return -1;
473	            }
474	            slice_at_target = (uint64_t) v;
475	            slice_consume_mode = 1;
476	        } else {
477	            fprintf(stderr, "hybrid_handoff: unknown option: %s\n", argv[i]);
478	            return -1;
479	        }
480	    }
481	    if (!outfile_path) {
482	        fputs("hybrid_handoff: outfile=PATH is required\n", stderr);
483	        return -1;
484	    }
485	    if (pc_mode) {
486	        fprintf(stderr,
487	                "hybrid_handoff: PC-mode enter=0x%" PRIx64 "\n",
488	                enter_pc_arg);
489	    }
490	    if (icount_mode) {
491	        fprintf(stderr,
492	                "hybrid_handoff: icount-mode target=%" PRIu64 "\n",
493	                icount_target);
494	    }
495	    if (bbv_mode) {
496	        if (bbv_slice_target == 0) {
497	            fputs("hybrid_handoff: bbv_out= requires slice=N\n", stderr);
498	            return -1;
499	        }
500	        bbv_emit = bbv_emit_new(bbv_out_path, bbv_slice_target);
501	        if (!bbv_emit) {
502	            fprintf(stderr, "hybrid_handoff: failed to open bbv_out=%s\n",
503	                    bbv_out_path);
504	            return -1;
505	        }
506	        fprintf(stderr,
507	                "hybrid_handoff: bbv-mode out=%s slice=%" PRIu64 "\n",
508	                bbv_out_path, bbv_slice_target);
509	    }
510	    if (slice_consume_mode) {
511	        if (bbv_slice_target == 0) {
512	            fputs("hybrid_handoff: slice_at= requires slice=N\n", stderr);
513	            return -1;
514	        }
515	        fprintf(stderr,
516	                "hybrid_handoff: slice-consume mode slice=%" PRIu64
517	                " slice_at=%" PRIu64 "\n",
518	                bbv_slice_target, slice_at_target);
519	    }
520	
521	    vcpu_state = qemu_plugin_scoreboard_new(sizeof(VcpuRegs));
522	    qemu_plugin_register_vcpu_tb_trans_cb(id, vcpu_tb_trans);
523	    return 0;
524	}
