177	// Fetches a qXfer:features:read annex in full, looping while the stub
178	// answers with the 'm' (more) marker. QEMU's RISC-V CSR XML is ~6 KB and
179	// PacketSize is typically 1000 bytes, so several iterations are normal.
180	inline auto fetch_feature_xml(gdbstub::Session& sess, const std::string& annex)
181	  -> std::string
182	{
183	  std::string accum;
184	  std::size_t offset = 0;
185	  // Use a chunk size below the QEMU default PacketSize=1000. Asking for
186	  // 0x100 keeps each frame well under the wire limit even after the 'm'
187	  // marker and packet framing overhead.
188	  constexpr std::size_t kChunk = 0x100;
189	  while (true) {
190	    char buf[64];
191	    std::snprintf(buf, sizeof(buf), ":%zx,%zx", offset, kChunk);
192	    auto body = sess.send_command("qXfer:features:read:" + annex + buf);
193	    if (body.empty())
194	      throw std::runtime_error("qXfer empty reply for " + annex);
195	    const char marker = body.front();
196	    if (marker != 'l' && marker != 'm')
197	      throw std::runtime_error("qXfer non-l/m reply for " + annex + ": "
198	                               + std::string{marker});
199	    accum.append(body.substr(1));
200	    if (marker == 'l') return accum;

200	    if (marker == 'l') return accum;
201	    offset += body.size() - 1;
202	  }
203	}
