205	// Walks target.xml and every <xi:include> annex, returning the merged
206	// register-name -> packet-number map.
207	inline auto discover_reg_map(gdbstub::Session& sess) -> gdbstub::RegMap
208	{
209	  gdbstub::RegMap map;
210	  const auto target_xml = fetch_feature_xml(sess, "target.xml");
211	  unsigned next = 0;
212	  for (const auto& annex : gdbstub::parse_target_xml(target_xml)) {
213	    const auto annex_xml = fetch_feature_xml(sess, annex);
214	    gdbstub::parse_feature_xml(annex_xml, map, next);
215	  }
216	  return map;
217	}
