280	// apply_state writes all architectural state fields to the gdbstub session.
281	// Templated on Session so tests can inject a recording stub without a real
282	// TCP socket (duck-type: needs send_command(string_view)->string).
283	template<class Session>
284	inline void apply_state(Session& sess,
285	                        const gdbstub::RegMap& reg_map,
286	                        const hybrid_state_v1& state)
287	{
288	  // RV64 core: x0..x31 = 0..31, pc = 32. Hard-coded because the core
289	  // feature is always first.
290	  for (unsigned i = 1; i < 32; ++i) {
291	    auto reply = sess.send_command(gdbstub::encode_p_body(i, state.gpr[i]));
292	    if (reply != "OK")
293	      throw std::runtime_error(
294	        "gdbstub: P packet for x" + std::to_string(i) + " replied " + reply);
295	  }
296	  auto reply = sess.send_command(gdbstub::encode_p_body(32, state.pc));
297	  if (reply != "OK")
298	    throw std::runtime_error("gdbstub: P32 (pc) replied " + reply);
299	
300	  if ((state.flags & HYBRID_FLAG_FP) != 0u)
301	    for (std::size_t i = 0; i < 32; ++i)
302	      try_write_named_u64(sess, reg_map, hybrid_fpr_names[i], state.fpr[i]);
303	
304	  for (const auto& slot : kCsrByName)
305	    try_write_named_u64(sess, reg_map, slot.first, state.*(slot.second));
306	
307	  for (uint16_t i = 0; i < HYBRID_PMP_CFG_NUM; ++i)
308	    try_write_named_u64(sess, reg_map, "pmpcfg" + std::to_string(i),
309	                        state.pmpcfg[i]);
310	  for (uint16_t i = 0; i < HYBRID_PMP_ADDR_NUM; ++i)
311	    try_write_named_u64(sess, reg_map, "pmpaddr" + std::to_string(i),
312	                        state.pmpaddr[i]);
313	
314	  if ((state.flags & HYBRID_FLAG_V) != 0u && state.vlenb > 0u
315	      && state.vlenb <= HYBRID_VLEN_BYTES_MAX) {
316	    try_write_named_u64(sess, reg_map, "vstart", state.vstart);
317	    try_write_named_u64(sess, reg_map, "vxsat",  state.vxsat);
318	    try_write_named_u64(sess, reg_map, "vxrm",   state.vxrm);
319	    try_write_named_u64(sess, reg_map, "vcsr",   state.vcsr);
320	    try_write_named_u64(sess, reg_map, "vtype",  state.vtype);
321	    try_write_named_u64(sess, reg_map, "vl",     state.vl);
322	    const std::size_t vbytes = static_cast<std::size_t>(state.vlenb);
323	    for (uint16_t i = 0; i < 32; ++i) {
324	      const std::string name = "v" + std::to_string(i);
325	      try_write_named_bytes(
326	        sess, reg_map, name,
327	        &state.vreg[static_cast<std::size_t>(i) * HYBRID_VLEN_BYTES_MAX],
328	        vbytes);
329	    }
330	  }
331	}
