335	// Restores x1..x31, PC, FPR (if HYBRID_FLAG_FP), M-mode CSRs, PMP, and
336	// vector data regs (if HYBRID_FLAG_V) into the QEMU vCPU via the gdbstub
337	// at `port`, then continues. Caller is responsible for waitpid().
338	inline void restore_state_via_gdbstub(uint16_t port,
339	                                      const hybrid_state_v1& state,
340	                                      pid_t child_pid = -1)
341	{
342	  spdlog::info("hybrid handback: connecting to gdbstub on tcp::{}", port);
343	  const int fd = detail::connect_loopback(port, std::chrono::seconds(5),
344	                                          child_pid);
345	  spdlog::info("hybrid handback: connected, discovering register map");
346	  gdbstub::Session sess{fd};
347	
348	  const auto reg_map = detail::discover_reg_map(sess);
349	  spdlog::info("hybrid handback: {} registers advertised, restoring state",
350	               reg_map.size());
351	
352	  detail::apply_state(sess, reg_map, state);
353	
354	  spdlog::info("hybrid handback: continuing target");
355	  sess.cont();
356	}
