358	// Top-level: spawns QEMU, restores state, waits for exit, returns exit
359	// status (or 128 + signal for abnormal termination).
360	inline auto run_qemu_handback(const std::string& qemu_binary,
361	                              const std::string& elf_path,
362	                              const hybrid_state_v1& state,
363	                              const std::string& shared_mem_path = {},
364	                              uint64_t shared_mem_size = 0) -> int
365	{
366	  const auto port = detail::pick_free_port();
367	  spdlog::info("hybrid handback: spawning {} -gdb tcp::{} -S",
368	               qemu_binary, port);
369	  const pid_t pid = detail::spawn_qemu(qemu_binary, elf_path, port,
370	                                       shared_mem_path, shared_mem_size);
371	
372	  try {
373	    restore_state_via_gdbstub(port, state, pid);
374	  } catch (const detail::ChildExitedDuringConnect& d) {
375	    return d.status;
376	  } catch (...) {
377	    ::kill(pid, SIGKILL);
378	    int wstat = 0;
379	    ::waitpid(pid, &wstat, 0);
380	    throw;
381	  }
382	
383	  int wstat = 0;
384	  if (::waitpid(pid, &wstat, 0) < 0)
385	    throw std::runtime_error(std::string{"waitpid: "}
386	                             + std::strerror(errno));
387	  if (WIFEXITED(wstat)) return WEXITSTATUS(wstat);
388	  if (WIFSIGNALED(wstat)) return 128 + WTERMSIG(wstat);
389	  return -1;
390	}
